import { Injectable } from '@nestjs/common';
import type { PointsConfig } from '@smartcart/shared-types';
import type {
  ShoppingSession,
  SessionItem,
} from '../../domain/entities/shopping-session.entity';
import { PointsStrategyResolver } from './points-strategy-resolver';

/**
 * Points calculation service (README §2.3 Points, §2.8 Workflow 1 step 4).
 *
 * The per-line value is computed at SCAN time via the Strategy pattern
 * (`calculateForItem`) and frozen onto `SessionItem.pointsValue`. At validation,
 * the awarded total is the sum of those frozen lines (`calculatePoints`) — this
 * is exactly the README "resolve strategy per item, sum" algorithm, evaluated
 * once at scan so the POS path needs no product configs.
 */
@Injectable()
export class PointsService {
  constructor(private readonly resolver: PointsStrategyResolver) {}

  /** Points for one scanned line, via the strategy for its config type. */
  calculateForItem(
    item: Pick<SessionItem, 'quantity' | 'unitPrice'>,
    config: PointsConfig,
  ): number {
    return this.resolver
      .resolve(config.type)
      .calculate(item as SessionItem, config);
  }

  /** Total awarded at checkout = sum of frozen per-line pending points. */
  calculatePoints(session: ShoppingSession): number {
    return session.items.reduce((total, item) => total + item.pointsValue, 0);
  }
}
